function makeSid(len = 48) {
  const alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_";
  let out = "";
  // Mix time + random to reduce collisions
  let seed = Date.now().toString(36) + "-" + Math.random().toString(36).slice(2);

  out += seed.replace(/[^a-z0-9-]/gi, "").slice(0, 12);

  while (out.length < len) {
    out += alphabet[Math.floor(Math.random() * alphabet.length)];
  }
  return out.slice(0, len);
}

const sid = makeSid(64);

return { json: { sid } };

function makeToken(len = 32) {
  let out = '';
  while (out.length < len) {
    out += Math.random().toString(36).slice(2); // Strip the leading "0."
  }
  return out.slice(0, len);
}
const token = makeToken()
return {token};

function generatePassword(length = 12) {
  const chars = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
  let out = '';
  for (let i = 0; i < length; i++) {
    const idx = Math.floor(Math.random() * chars.length);
    out += chars[idx];
  }
  return out;
